import React, { useEffect, useState, useRef } from "react";
import { Link, useNavigate } from 'react-router-dom';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "../../../../utils/Common";
import { CButton } from "@coreui/react";
import { deleteDepartment, fetchAllDepartmentData } from "../../../../components/services/CareerApi";
import { customStyles } from "../../../../utils/tableCustomStyles";
import { tableDepartmentConstant } from "../tableDepartmentConstant";
import DataTable from "react-data-table-component";
import ExportCSV from "../../../../utils/ExportCsvButton";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const headers = [
    { label: "Department", key: "name" },
    { label: "Status", key: "status" },
    { label: "Created By", key: "createdBy" }
];

function ListDepartment() {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchDepartmentList();
    }, []);

    const fetchDepartmentList = async () => {
        const department = await fetchAllDepartmentData();
        if (department?.code === 200) {
            setRowData(department?.results);
        }
    };

    const handleDelete = async (id) => {
        let response = await deleteDepartment(id);
        if (response?.code === 200) {
            fetchDepartmentList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const actionButton = () => {
        return (
            <React.Fragment>
               {authService.getPermission("DEPARTMENT_EXPORT_CSV") && rowData?.length > 0 &&  <ExportCSV headers={headers} data={rowData} filename="department_list" />}
            </React.Fragment>
        );
    };

    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="Department"
                    columns={tableDepartmentConstant(fetchDepartmentList, handleConfirmModal)}
                    data={rowData}
                    customStyles={customStyles}
                    actions={actionButton()}
                    pagination
                    paginationPerPage={10}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>
            {authService.getPermission("DEPARTMENT_CREATE") && <div className='col-sm-12'>
                <Link to={"/career/department/create"}>
                    <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                        {"+ Create Department"}
                    </CButton>
                </Link>
            </div>}
        </div>
    );
}

export default ListDepartment;
